import { Component, OnInit } from '@angular/core';
import { UsuariService } from '../../services/usuari.service';
import { ResultatService } from '../../services/resultat.service';

@Component({
  selector: 'app-ranking',
  templateUrl: './ranking.component.html'
})
export class RankingComponent implements OnInit {
  usuaris: any[] = [];
  loading = true;
  error = '';

  constructor(private usuariService: UsuariService) {}

  ngOnInit(): void {
    this.usuariService.getRanking().subscribe({
      next: (u) => {
        this.usuaris = u;
        this.loading = false;
      },
      error: () => {
        this.error = 'No s\'ha pogut carregar el rànquing.';
        this.loading = false;
      }
    });
  }

  nivellLabel(n: string): string {
    const m: any = { BASIC: 'Bàsic', INTERMEDIATE: 'Intermedi', ADVANCED: 'Avançat' };
    return m[n] || n;
  }

  medallaClass(i: number): string {
    if (i === 0) return 'text-warning fw-bold';
    if (i === 1) return 'text-secondary fw-bold';
    if (i === 2) return 'text-danger-emphasis fw-bold';
    return '';
  }
}
<h4 class="mb-4"><i class="bi bi-list-ol me-2"></i>Rànquing global</h4>

<div class="alert alert-danger" *ngIf="error">{{ error }}</div>

<div class="text-center py-5" *ngIf="loading">
  <div class="spinner-border"></div>
</div>

<div *ngIf="!loading">
  <div class="table-responsive">
    <table class="table table-hover align-middle">
      <thead class="table-dark">
        <tr>
          <th style="width:60px">#</th>
          <th>Nom</th>
          <th>Email</th>
          <th>Nivell</th>
          <th>Rol</th>
        </tr>
      </thead>
      <tbody>
        <tr *ngFor="let u of usuaris; let i = index">
          <td [ngClass]="medallaClass(i)">
            <i class="bi bi-trophy-fill me-1" *ngIf="i === 0"></i>
            <i class="bi bi-award-fill me-1" *ngIf="i === 1"></i>
            <i class="bi bi-award me-1" *ngIf="i === 2"></i>
            {{ i + 1 }}
          </td>
          <td>{{ u.nom }} {{ u.cognoms }}</td>
          <td class="text-muted small">{{ u.email }}</td>
          <td>
            <span class="badge bg-secondary">{{ nivellLabel(u.nivell) }}</span>
          </td>
          <td>
            <span class="badge bg-dark">{{ u.rol }}</span>
          </td>
        </tr>
      </tbody>
    </table>
  </div>
  <p class="text-muted small">* El rànquing és de només lectura.</p>
</div>
